using System.ClientModel;
using Microsoft.Extensions.AI;
using OpenAI;

// Configuration via environment variables
var endpoint = Environment.GetEnvironmentVariable("OPENAI_ENDPOINT") ?? "https://api.openai.com/v1";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new InvalidOperationException(
    "Set the OPENAI_API_KEY environment variable.");
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

// Build the AI chat client with tool support
var openAiClient = new OpenAIClient(new ApiKeyCredential(apiKey), new OpenAIClientOptions
{
    Endpoint = new Uri(endpoint)
});

var notepad = new Notepad();

IChatClient chatClient = openAiClient.GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Register tools
var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearch.SearchAsync),
    AIFunctionFactory.Create(notepad.AddNote),
    AIFunctionFactory.Create(notepad.GetNotes),
};

var chatOptions = new ChatOptions { Tools = tools };

// Prompt the user for a research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// Run the agent loop
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to research the given topic thoroughly.
        Use the web_search tool to find information, and the add_note tool to record
        key findings as you go. Search multiple queries to get a well-rounded view.
        After gathering enough information, use get_notes to review your notes,
        then provide a comprehensive summary of your findings to the user.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
};

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("== Research Summary ==\n");
Console.WriteLine(response.Text);

Console.WriteLine("\n== Notes Collected ==");
foreach (var note in notepad.AllNotes)
{
    Console.WriteLine($"  • {note}");
}

// --- Tool Definitions ---

/// <summary>Simulates web search results for a query.</summary>
static class WebSearch
{
    [System.ComponentModel.Description("Search the web for information on a given query. Returns relevant snippets.")]
    public static async Task<string> SearchAsync(
        [System.ComponentModel.Description("The search query")] string query)
    {
        // Simulate network delay
        await Task.Delay(100);

        // In production, call a real search API (Bing, Google, etc.)
        return $"""
            Search results for: "{query}"

            1. [Wikipedia] Overview article discussing key aspects of {query}, including historical context and recent developments.
            2. [News] Recent coverage highlighting new findings and expert opinions on {query}.
            3. [Academic] A peer-reviewed study examining the impact and implications of {query} across multiple dimensions.
            4. [Industry Report] Market analysis and trend data related to {query}, showing growth patterns and forecasts.
            """;
    }
}

/// <summary>A notepad tool for the agent to record and retrieve research findings.</summary>
class Notepad
{
    private readonly List<string> _notes = [];

    public IReadOnlyList<string> AllNotes => _notes;

    [System.ComponentModel.Description("Add a research note to remember a key finding.")]
    public string AddNote(
        [System.ComponentModel.Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note saved ({_notes.Count} total).";
    }

    [System.ComponentModel.Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return "Saved notes:\n" + string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

